'use client'

import {
  cn,
  DismissableLayer,
  Presence,
  useAnchorPosition,
  useRovingFocus,
  useSignal,
  useSignals,
  type RovingOrientation,
} from '@cascivo/core'
import { useId, useRef, type CSSProperties, type KeyboardEvent, type ReactNode } from 'react'
import styles from './navigation-menu.module.css'

export interface NavigationMenuItem {
  id: string
  label: ReactNode
  href?: string
  content?: ReactNode
}

export interface NavigationMenuProps {
  items: NavigationMenuItem[]
  'aria-label'?: string
  orientation?: RovingOrientation
  className?: string
}

export function NavigationMenu({
  items,
  'aria-label': ariaLabel,
  orientation = 'horizontal',
  className,
}: NavigationMenuProps) {
  useSignals()
  const baseId = useId()
  const openId = useSignal<string | null>(null)
  const roving = useRovingFocus({ orientation, loop: true })

  return (
    <nav
      aria-label={ariaLabel}
      className={cn(styles['nav'], className)}
      data-orientation={orientation}
    >
      <ul role="list" className={styles['list']}>
        {items.map((item, index) => (
          <NavigationMenuEntry
            key={item.id}
            item={item}
            baseId={baseId}
            openId={openId}
            itemProps={roving.getItemProps(index)}
          />
        ))}
      </ul>
    </nav>
  )
}

interface NavigationMenuEntryProps {
  item: NavigationMenuItem
  baseId: string
  openId: ReturnType<typeof useSignal<string | null>>
  itemProps: ReturnType<ReturnType<typeof useRovingFocus>['getItemProps']>
}

function NavigationMenuEntry({ item, baseId, openId, itemProps }: NavigationMenuEntryProps) {
  useSignals()
  const triggerRef = useRef<HTMLButtonElement>(null)
  const floatingRef = useRef<HTMLDivElement>(null)
  const hasContent = item.content != null
  const isOpen = openId.value === item.id
  const panelId = `${baseId}-panel-${item.id}`

  const { anchorStyle, floatingStyle } = useAnchorPosition({
    anchorRef: triggerRef,
    floatingRef,
    placement: 'bottom-start',
    enabled: isOpen,
  })

  const { ref: rovingRef, onKeyDown: rovingKeyDown, ...rovingRest } = itemProps

  if (!hasContent) {
    return (
      <li className={styles['item']}>
        <a
          ref={(el) => rovingRef(el)}
          href={item.href}
          className={styles['link']}
          onKeyDown={rovingKeyDown}
          {...rovingRest}
        >
          {item.label}
        </a>
      </li>
    )
  }

  const handleKeyDown = (event: KeyboardEvent<HTMLButtonElement>): void => {
    rovingKeyDown(event)
    if (event.defaultPrevented) return
    if (event.key === 'Escape') {
      openId.value = null
    }
  }

  return (
    <li className={styles['item']}>
      <button
        ref={(el) => {
          triggerRef.current = el
          rovingRef(el)
        }}
        type="button"
        aria-expanded={isOpen}
        aria-controls={panelId}
        data-state={isOpen ? 'open' : 'closed'}
        className={styles['trigger']}
        style={anchorStyle}
        onClick={() => {
          openId.value = isOpen ? null : item.id
        }}
        onKeyDown={handleKeyDown}
        {...rovingRest}
      >
        {item.label}
      </button>
      <Presence present={isOpen}>
        <NavigationMenuPanel
          panelId={panelId}
          floatingRef={floatingRef}
          floatingStyle={floatingStyle}
          onClose={() => {
            openId.value = null
            triggerRef.current?.focus()
          }}
        >
          {item.content}
        </NavigationMenuPanel>
      </Presence>
    </li>
  )
}

interface NavigationMenuPanelProps {
  panelId: string
  floatingRef: React.RefObject<HTMLDivElement | null>
  floatingStyle: CSSProperties
  onClose: () => void
  children: ReactNode
}

function NavigationMenuPanel({
  panelId,
  floatingRef,
  floatingStyle,
  onClose,
  children,
}: NavigationMenuPanelProps) {
  return (
    <DismissableLayer onDismiss={onClose}>
      <div ref={floatingRef} id={panelId} className={styles['panel']} style={floatingStyle}>
        {children}
      </div>
    </DismissableLayer>
  )
}

@layer cascivo.component {
  .nav {
    display: inline-flex;
  }

  .list {
    display: flex;
    align-items: center;
    gap: var(--cascivo-space-1);
    margin: 0;
    padding: 0;
    list-style: none;
  }

  .nav[data-orientation='vertical'] .list {
    flex-direction: column;
    align-items: stretch;
  }

  .item {
    position: relative;
  }

  .link,
  .trigger {
    display: inline-flex;
    align-items: center;
    gap: var(--cascivo-space-1);
    padding-block: var(--cascivo-space-2);
    padding-inline: var(--cascivo-space-3);
    background: transparent;
    border: none;
    border-radius: var(--cascivo-radius-item);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text);
    text-decoration: none;
    cursor: pointer;

    &:hover,
    &[data-state='open'] {
      background: var(--cascivo-color-bg-subtle);
    }

    &:focus-visible {
      outline: var(--cascivo-focus-ring);
      outline-offset: 2px;
    }
  }

  .panel {
    position: fixed;
    inset: auto;
    margin: 0;
    padding: var(--cascivo-space-3);
    min-width: 12rem;
    background: var(--cascivo-color-surface);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-overlay);
    box-shadow: var(--cascivo-shadow-md);

    opacity: 1;
    translate: 0 0;
    transition:
      opacity var(--cascivo-motion-enter),
      translate var(--cascivo-motion-enter);

    @starting-style {
      opacity: 0;
      translate: 0 calc(-1 * var(--cascivo-space-2));
    }

    &[data-state='closed'] {
      opacity: 0;
      translate: 0 calc(-1 * var(--cascivo-space-2));
      transition:
        opacity var(--cascivo-motion-exit),
        translate var(--cascivo-motion-exit);
    }
  }
}

@media (prefers-reduced-motion: reduce) {
  .panel {
    transition: none;
  }
}

@media (forced-colors: active) {
  .link:focus-visible,
  .trigger:focus-visible {
    outline: 2px solid Highlight;
  }
}
